if records:
    # Filtrar solo documentos exitosos no-credit_note
    valid = records.filtered(lambda r: r.state_dian == 'exitoso' and not r.credit_note)
    if not valid:
        raise UserError("Seleccione documentos exitosos (no notas de ajuste) para crear ajustes masivos.")
    action = {
        'type': 'ir.actions.act_window',
        'name': 'Crear Ajustes Masivos',
        'res_model': 'hr.payslip.edi.batch.adjustment',
        'view_mode': 'form',
        'target': 'new',
        'context': {
            'default_source_ids': [(6, 0, valid.ids)],
        },
    }
